class SQSWorker:
    def __init__(
        self,
        queue_url: str,
        region_name: str = 'us-east-1',
        max_messages: int = 10,
        wait_time_seconds: int = 20,
        visibility_timeout: int = 30
    ):
        self.queue_url = queue_url
        self.max_messages = max_messages
        self.wait_time_seconds = wait_time_seconds
        self.visibility_timeout = visibility_timeout
        
        self.sqs_client = boto3.client('sqs', region_name=region_name)
        self.handlers: Dict[str, MessageHandler] = {}
        self.running = False
        
        self._register_default_handlers()
    
    def _register_default_handlers(self):
        self.register_handler('email', EmailMessageHandler())
        self.register_handler('data_processing', DataProcessingHandler())
        self.register_handler('notification', NotificationHandler())
        self.register_handler('report_generation', ReportGenerationHandler())
        self.register_handler('file_processing', FileProcessingHandler())
        self.register_handler('database_operation', DatabaseOperationHandler())
    
    def register_handler(self, message_type: str, handler: MessageHandler):
        self.handlers[message_type] = handler
        logger.info(f"Registered handler for message type: {message_type}")
    
    def poll_messages(self):
        try:
            response = self.sqs_client.receive_message(
                QueueUrl=self.queue_url,
                MaxNumberOfMessages=self.max_messages,
                WaitTimeSeconds=self.wait_time_seconds,
                VisibilityTimeout=self.visibility_timeout,
                AttributeNames=['All'],
                MessageAttributeNames=['All']
            )
            
            messages = response.get('Messages', [])
            logger.info(f"Received {len(messages)} messages from queue")
            return messages
        
        except Exception as e:
            logger.error(f"Error polling messages: {str(e)}")
            return []
    
    def parse_message(self, message: Dict[str, Any]) -> Optional[Dict[str, Any]]:
        try:
            body = message.get('Body', '{}')
            parsed_body = json.loads(body)
            
            message_type = parsed_body.get('type')
            message_data = parsed_body.get('data', {})
            
            if not message_type:
                logger.warning("Message missing 'type' field")
                return None
            
            return {
                'type': message_type,
                'data': message_data,
                'receipt_handle': message.get('ReceiptHandle'),
                'message_id': message.get('MessageId'),
                'attributes': message.get('Attributes', {}),
                'message_attributes': message.get('MessageAttributes', {})
            }
        
        except json.JSONDecodeError as e:
            logger.error(f"Failed to parse message body: {str(e)}")
            return None
        except Exception as e:
            logger.error(f"Error parsing message: {str(e)}")
            return None
    
    def process_message(self, parsed_message: Dict[str, Any]) -> bool:
        message_type = parsed_message['type']
        message_data = parsed_message['data']
        message_id = parsed_message['message_id']
        
        logger.info(f"Processing message {message_id} of type: {message_type}")
        
        handler = self.handlers.get(message_type)
        
        if not handler:
            logger.warning(f"No handler registered for message type: {message_type}")
            return False
        
        try:
            start_time = time.time()
            success = handler.handle(message_data)
            elapsed_time = time.time() - start_time
            
            if success:
                logger.info(f"Successfully processed message {message_id} in {elapsed_time:.2f}s")
            else:
                logger.warning(f"Handler returned False for message {message_id}")
            
            return success
        
        except Exception as e:
            logger.error(f"Error processing message {message_id}: {str(e)}")
            return False
    
    def delete_message(self, receipt_handle: str):
        try:
            self.sqs_client.delete_message(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle
            )
            logger.info("Message deleted from queue")
        except Exception as e:
            logger.error(f"Error deleting message: {str(e)}")
    
    def change_message_visibility(self, receipt_handle: str, visibility_timeout: int):
        try:
            self.sqs_client.change_message_visibility(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle,
                VisibilityTimeout=visibility_timeout
            )
            logger.info(f"Changed message visibility to {visibility_timeout} seconds")
        except Exception as e:
            logger.error(f"Error changing message visibility: {str(e)}")
    
    def process_batch(self, messages):
        for message in messages:
            parsed_message = self.parse_message(message)
            
            if not parsed_message:
                logger.warning("Skipping invalid message")
                continue
            
            success = self.process_message(parsed_message)
            
            if success:
                self.delete_message(parsed_message['receipt_handle'])
            else:
                logger.warning("Message processing failed, will retry after visibility timeout")
    
    def start(self, continuous: bool = True):
        self.running = True
        logger.info(f"Starting SQS worker for queue: {self.queue_url}")
        
        try:
            while self.running:
                messages = self.poll_messages()
                
                if messages:
                    self.process_batch(messages)
                else:
                    logger.info("No messages received")
                
                if not continuous:
                    break
                
                time.sleep(1)
        
        except KeyboardInterrupt:
            logger.info("Received interrupt signal, stopping worker...")
            self.stop()
        except Exception as e:
            logger.error(f"Worker error: {str(e)}")
            self.stop()
    
    def stop(self):
        self.running = False
        logger.info("SQS worker stopped")


